// Filter clients with Meta Ad Account ID and extract needed fields
const records = $input.first().json.records || [];
const clients = records
  .filter(r => r.fields['Meta Ad Account ID'])
  .map(r => ({
    name: r.fields.Firmenname || r.fields.Name || '',
    ad_account_id: String(r.fields['Meta Ad Account ID']).replace('act_', ''),
    email: r.fields['AP E-Mail'] || r.fields.Email || '',
    sheet_id: extractSheetId(r.fields['Reporting Sheet'] || ''),
    weekly_budget: r.fields.Wochenbudget || 0,
    airtable_id: r.id
  }))
  .filter(c => c.sheet_id);

function extractSheetId(url) {
  const m = url.match(/\/d\/([a-zA-Z0-9_-]+)/);
  return m ? m[1] : url;
}

return clients.map(c => ({ json: c }));

// Combine daily + campaign data, build sheet rows
const client = $('Filter & Transform Clients').item.json;
const dailyData = $('Meta: Daily Insights').item.json.data || [];
const campData = $('Meta: Campaign Insights').item.json.data || [];

const kw = getWeekNumber(new Date());
const since = new Date(Date.now() - 7*86400000).toISOString().split('T')[0];
const until = new Date(Date.now() - 86400000).toISOString().split('T')[0];

function getWeekNumber(d) {
  d = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay()||7));
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(),0,1));
  return Math.ceil((((d - yearStart) / 86400000) + 1)/7);
}

function extractAction(actions, types) {
  if (!actions) return 0;
  for (const t of types) {
    const found = actions.find(a => a.action_type === t);
    if (found) return parseFloat(found.value) || 0;
  }
  return 0;
}

const purchaseTypes = ['offsite_conversion.fb_pixel_purchase', 'purchase', 'omni_purchase'];

// Daily rows for Charts Data tab
const dailyRows = [['Datum','Spend','Impressions','Clicks','CTR','CPC','CPM','ROAS','Purchases','Revenue']];
let totalSpend = 0, totalImp = 0, totalClicks = 0, totalPurchases = 0, totalRevenue = 0;

for (const d of dailyData.sort((a,b) => a.date_start.localeCompare(b.date_start))) {
  const spend = parseFloat(d.spend || 0);
  const imp = parseInt(d.impressions || 0);
  const clicks = parseInt(d.clicks || 0);
  const purchases = extractAction(d.actions, purchaseTypes);
  const revenue = extractAction(d.action_values, purchaseTypes);
  const roas = d.purchase_roas?.[0]?.value ? parseFloat(d.purchase_roas[0].value) : (spend > 0 ? revenue/spend : 0);
  totalSpend += spend; totalImp += imp; totalClicks += clicks; totalPurchases += purchases; totalRevenue += revenue;
  dailyRows.push([d.date_start, Math.round(spend*100)/100, imp, clicks, Math.round(parseFloat(d.ctr||0)*100)/100, Math.round(parseFloat(d.cpc||0)*100)/100, Math.round(parseFloat(d.cpm||0)*100)/100, Math.round(roas*100)/100, purchases, Math.round(revenue*100)/100]);
}

// Campaign rows
const campRows = [['Campaign','Objective','Spend','Impressions','Clicks','CTR','Purchases','Revenue','ROAS','CPA']];
for (const c of campData.sort((a,b) => parseFloat(b.spend||0) - parseFloat(a.spend||0))) {
  const spend = parseFloat(c.spend||0);
  const purchases = extractAction(c.actions, purchaseTypes);
  const revenue = extractAction(c.action_values, purchaseTypes);
  campRows.push([c.campaign_name, c.objective, Math.round(spend*100)/100, parseInt(c.impressions||0), parseInt(c.clicks||0), Math.round(parseFloat(c.ctr||0)*100)/100, purchases, Math.round(revenue*100)/100, spend>0?Math.round(revenue/spend*100)/100:0, purchases>0?Math.round(spend/purchases*100)/100:0]);
}

// Summary
const avgCtr = totalImp > 0 ? Math.round(totalClicks/totalImp*10000)/100 : 0;
const avgRoas = totalSpend > 0 ? Math.round(totalRevenue/totalSpend*100)/100 : 0;
const cpa = totalPurchases > 0 ? Math.round(totalSpend/totalPurchases*100)/100 : 0;
const wb = client.weekly_budget || 0;

const summaryRows = [
  ['Weekly Performance Summary'],
  [`Zeitraum: ${since} bis ${until} (KW${kw})`],
  [''],
  ['📊 KPIs',''],
  ['Total Spend', `€${totalSpend.toFixed(2)}`],
  ['Impressions', totalImp.toLocaleString()],
  ['Clicks', totalClicks.toLocaleString()],
  ['CTR', `${avgCtr}%`],
  ['Purchases', totalPurchases],
  ['Revenue', `€${totalRevenue.toFixed(2)}`],
  ['ROAS', `${avgRoas}x`],
  ['Cost per Purchase', `€${cpa}`],
  [''],
  ['💰 Budget Status',''],
  ['Wochenbudget', wb ? `€${wb.toFixed(2)}` : 'N/A'],
  ['Ausgegeben', `€${totalSpend.toFixed(2)}`],
  ['Verbrauch', wb ? `${Math.round(totalSpend/wb*100)}%` : 'N/A'],
];

return [{
  json: {
    ...client,
    kw,
    since,
    until,
    summary: { totalSpend, totalImp, totalClicks, avgCtr, totalPurchases, totalRevenue, avgRoas, cpa },
    sheets: { dailyRows, campRows, summaryRows }
  }
}];

// Build HTML email from report data
const d = $input.first().json;
const s = d.summary;

const campTableRows = (d.sheets.campRows || []).slice(1, 6).map(c => 
  `<tr><td><strong>${c[0]}</strong></td><td>€${c[2]}</td><td>${c[8]}x</td><td>${c[5]}%</td><td>${c[6]}</td></tr>`
).join('\n');

const html = `<!DOCTYPE html>
<html><head><meta charset="utf-8"><style>
body{margin:0;padding:0;font-family:'Helvetica Neue',Arial,sans-serif;background:#f4f4f7;color:#333}
.c{max-width:640px;margin:0 auto;background:#fff}
.h{background:linear-gradient(135deg,#1a1a2e,#16213e);padding:32px 40px;text-align:center}
.h h1{color:#fff;font-size:22px;margin:0;font-weight:600}
.h .sub{color:#a0aec0;font-size:14px;margin-top:6px}
.s{padding:28px 40px}
.st{font-size:16px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:#1a1a2e;margin-bottom:16px;border-bottom:2px solid #e2e8f0;padding-bottom:8px}
.kg{display:flex;flex-wrap:wrap;gap:12px}
.kc{flex:1;min-width:120px;background:#f7fafc;border-radius:8px;padding:16px;text-align:center}
.kv{font-size:24px;font-weight:700;color:#1a1a2e}
.kl{font-size:11px;text-transform:uppercase;letter-spacing:.5px;color:#718096;margin-top:4px}
table{width:100%;border-collapse:collapse;font-size:13px}
th{text-align:left;padding:10px 12px;background:#f7fafc;color:#718096;font-size:11px;text-transform:uppercase}
td{padding:10px 12px;border-bottom:1px solid #edf2f7}
.btn{display:inline-block;background:#1a1a2e;color:#fff!important;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;font-size:14px;margin-top:16px}
.ft{background:#f7fafc;padding:24px 40px;text-align:center;font-size:12px;color:#a0aec0}
</style></head><body>
<div class="c">
<div class="h"><h1>Weekly Performance Report</h1><div class="sub">${d.name} · KW${d.kw} · ${d.since} – ${d.until}</div></div>
<div class="s"><div class="st">📊 Performance Overview</div>
<div class="kg">
<div class="kc"><div class="kv">€${s.totalSpend.toFixed(2)}</div><div class="kl">Ad Spend</div></div>
<div class="kc"><div class="kv">${s.avgRoas}x</div><div class="kl">ROAS</div></div>
<div class="kc"><div class="kv">${s.totalPurchases}</div><div class="kl">Conversions</div></div>
<div class="kc"><div class="kv">${s.avgCtr}%</div><div class="kl">CTR</div></div>
<div class="kc"><div class="kv">€${s.cpa}</div><div class="kl">Cost/Conv.</div></div>
</div></div>
<hr style="border:0;height:1px;background:#e2e8f0;margin:0">
<div class="s"><div class="st">🎯 Campaign Performance</div>
<table><thead><tr><th>Campaign</th><th>Spend</th><th>ROAS</th><th>CTR</th><th>Conv.</th></tr></thead>
<tbody>${campTableRows}</tbody></table></div>
<div class="s" style="text-align:center"><a href="https://docs.google.com/spreadsheets/d/${d.sheet_id}/edit" class="btn">📄 Zum vollständigen Report</a></div>
<div class="ft"><p>Automatisch erstellt von <strong>adsdrop</strong></p></div>
</div></body></html>`;

return [{ json: { ...d, emailHtml: html, emailSubject: `Weekly Performance Report - ${d.name} - KW${d.kw}` } }];
